	[1028] = {
		id = 1028,
		key = 'NewsPVPTopRank',
		text = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# for achieving top in the Arena with an unparalleled strength! It\'s probably true that it can be kinda lonely at the top...',
		text_tw = '#C0x5B545B#恭喜#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#以雷霆萬鈞之勢奪得競技場第一寶座，無敵也是一種寂寞…',
		text_en = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# for achieving top in the Arena with an unparalleled strength! It\'s probably true that it can be kinda lonely at the top...',
		text_vn = '#C0x5B545B#Chúc mừng#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#đã giành được ngôi vị quán quân đấu trường với sức mạnh áp đảo.  Bất khả chiến bại cũng là một sự cô đơn…',
		text_kr = '#C0x5B545B#축하합니다. #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# 님이 아레나 1위를 달성했습니다!',
		text_pt = '#C0x5B545B#Parabéns a #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# por atingir o topo na Arena com uma força inigualável! Provavelmente é verdade que pode ser meio solitário no topo...',
		text_th = '#C0x5B545B#ขอแสดงความยินดีกับ #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# สำหรับการขึ้นถึงจุดสูงสุดใน Arena ด้วยความแข็งแกร่งที่ไม่มีใครเทียบได้! อาจเป็นเรื่องจริงที่การขึ้นถึงจุดสูงสุดนั้นค่อนข้างจะโดดเดี่ยว...'
	},
	[1029] = {
		id = 1029,
		key = 'NewsYZPassFloor40',
		text = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# who reaches trial floor 40 after going through lots of difficulties! We hope you reach greater heights in the future!',
		text_tw = '#C0x5B545B#恭喜#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#歷盡艱辛後，達到寵物試煉40層，祝福ta更上一層樓！',
		text_en = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# who reaches trial floor 40 after going through lots of difficulties! We hope you reach greater heights in the future!',
		text_vn = '#C0x5B545B#Chúc mừng#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#đã vượt qua nhiều khó khăn để đạt đến tầng 40 của thử thách thú cưng! Chúc bạn ngày càng tiến xa hơn nữa!',
		text_kr = '#C0x5B545B#축하합니다. #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# 님이 고생 끝에 포켓몬 시련 40층에 도달했습니다!',
		text_pt = '#C0x5B545B#Parabéns a #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# que chega ao andar de teste 40 depois de passar por muitas dificuldades! Esperamos que você alcance alturas maiores no futuro!',
		text_th = '#C0x5B545B#ขอแสดงความยินดีกับ #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# ที่ผ่านชั้นทดสอบ 40 ได้สำเร็จหลังจากผ่านความยากลำบากมากมาย! หวังว่าคุณจะไปถึงจุดที่สูงกว่านี้ในอนาคต!'
	},
	[1030] = {
		id = 1030,
		key = 'NewsYZPassFloor50',
		text = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# who reaches trial floor 50 after going through lots of difficulties! Do keep up the good work and reach greater heights in the future!',
