		text_en = '#C0x5B545B#Congratulations to #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# who reaches trial floor 50 after going through lots of difficulties! Do keep up the good work and reach greater heights in the future!',
		text_vn = '#C0x5B545B#Chúc mừng#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#Sau bao nhiêu khó khăn, bạn đã đạt được tầng 50 của thử thách thú cưng! Chúc thú cưng của bạn ngày càng mạnh mẽ hơn!',
		text_kr = '#C0x5B545B#축하합니다. #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# 님이 고생 끝에 포켓몬 시련 50층에 도달했습니다!',
		text_pt = '#C0x5B545B#Parabéns a #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# que chega ao nível de teste 50 depois de passar por muitas dificuldades! Continue com o bom trabalho e alcance patamares maiores no futuro!',
		text_th = '#C0x5B545B#ขอแสดงความยินดีกับ #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B# ที่ผ่านชั้นทดสอบ 50 ได้สำเร็จหลังจากผ่านความยากลำบากมากมาย! ขอให้รักษาผลงานดีๆ ไว้และก้าวไปสู่จุดที่สูงกว่าในอนาคต!'
