		text = '#C0x5C9971#%s#C0x5B545B#is being surrounded in the %s element room by #C0xE77421#%s#C0x5B545B#! Hurry, offer them some assistance#LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_tw = '#C0x5C9971#%s#C0x5B545B#正在%s元素房間被#C0xE77421#%s#C0x5B545B#圍堵，快來前往協助#LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_en = '#C0x5C9971#%s#C0x5B545B#is being surrounded in the %s element room by #C0xE77421#%s#C0x5B545B#! Hurry, offer them some assistance#LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_vn = '#C0x5C9971#%s#C0x5B545B#đang bị bao vây trong phòng nguyên tố %s bởi #C0xE77421#%s#C0x5B545B#, hãy nhanh chóng đến hỗ trợ #LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_kr = '#C0x5C9971#%s#C0x5B545B# 님이 %s 엘리먼트 방에서 #C0xE77421#%s#C0x5B545B#에게 포위되었습니다. 어서 도와주세요! #LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_pt = '#C0x5C9971#%s#C0x5B545B#está sendo cercado na sala do elemento %s por #C0xE77421#%s#C0x5B545B#! Depressa, ofereça-lhes alguma assistência#LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_th = '#C0x5C9971#%s#C0x5B545B# กำลังถูกล้อมรอบในห้องธาตุ %s โดย #C0xE77421#%s#C0x5B545B#! รีบเสนอความช่วยเหลือให้พวกเขาหน่อย#LULnature_room_id##Icity/adventure/clone_battle/imag_ljjr.png-182-54#'
	},
	[1035] = {
		id = 1035,
		key = 'UnionRedPacketSend',
		text = 'The #C0x5B545B#Tycoon#C0x5C9971#{role}#C0x5B545B# has put up some rewards! Hurry, grab it now!#LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_tw = '#C0x5B545B#土豪#C0x5C9971#{role}#C0x5B545B#發福利啦，大家快去搶！#LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_en = 'The #C0x5B545B#Tycoon#C0x5C9971#{role}#C0x5B545B# has put up some rewards! Hurry, grab it now!#LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_vn = '#C0x5B545B#Đại gia#C0x5C9971#{role}#C0x5B545B#đang phát phúc lợi, mọi người nhanh tay tranh giành nào! #LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_kr = '#C0x5B545B##C0x5C9971#{role}#C0x5B545B# 님이 모두에게 보너스 혜택을 보냈습니다. 놓치지 마세요!#LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_pt = 'O #C0x5B545B#Tycoon#C0x5C9971#{role}#C0x5B545B# colocou algumas recompensas! Corra, pegue agora!#LULredpack##Icommon/btn/img_ljqw.png-182-54#',
		text_th = '#C0x5B545B#Tycoon#C0x5C9971#{role}#C0x5B545B# ได้มอบรางวัลมาให้แล้ว! รีบคว้ามันมาเลย! #LULredpack##Icommon/btn/img_ljqw.png-182-54#'
	},
	[1036] = {
		id = 1036,
		key = 'UnionRedPacketGetRole',
		text = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# is having Lady Luck on their side as they manage to grab  #C0xE69900#{count}{type}#C0x5B545B# from #C0x5C9971#{role_send}#C0x5B545B#\'s Red Packet!',
		text_tw = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B#鴻運當頭，搶到了#C0x5C9971#{role_send}#C0x5B545B#紅包裡的#C0xE69900#{count}{type}#C0x5B545B#！',
		text_en = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# is having Lady Luck on their side as they manage to grab  #C0xE69900#{count}{type}#C0x5B545B# from #C0x5C9971#{role_send}#C0x5B545B#\'s Red Packet!',
		text_vn = 'May mắn! Bạn đã nhận được #C0xE69900#{count}{type}#C0x5B545B# từ phong bao lì xì của #C0x5C9971#{role_send}#C0x5B545B#!',
		text_kr = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B#축하합니다! #C0x5C9971#{role_send}#C0x5B545B# 보너스에서 #C0xE69900#{count}{type}#C0x5B545B# 획득!',
		text_pt = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# está tendo a Sorte do seu lado enquanto eles conseguem pegar #C0xE69900#{count}{type}#C0x5B545B# do Pacote Vermelho de #C0x5C9971#{role_send}#C0x5B545B#!',
		text_th = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# กำลังมี Lady Luck เข้าข้างพวกเขาในขณะที่พวกเขาสามารถคว้า #C0xE69900#{count}{type}#C0x5B545B# จาก #C0x5C9971#{role_send}#C0x5B545B#'
	},
	[1037] = {
