		text_tw = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B#福星高照，搶到一個公會紅包，獲得了#C0xE69900#{count}{type}#C0x5B545B#！',
		text_en = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# is having Lady Luck on their side as they grabbed a union Red Packet which contain #C0xE69900#{count}{type}#C0x5B545B#!',
		text_vn = 'May mắn! Nhận được một phong bao lì xì bang hội và nhận được #C0xE69900#{count}{type}#C0x5B545B#!',
		text_kr = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# 축하합니다! 길드 보너스를 손에 넣어 #C0xE69900#{count}{type}#C0x5B545B# 획득!',
		text_pt = '#C0x5B545B##C0x5C9971#{role_get}#C0x5B545B# está tendo a Sorte do seu lado, pois eles pegaram um Pacote Vermelho da União que contém #C0xE69900#{count}{type}#C0x5B545B#!',
