	[1046] = {
		id = 1046,
		key = 'RoleNewJoinUnion',
		text = '#C0x5B545B#%s is requesting to join your union, please grant your approval!',
		text_tw = '#C0x5B545B#%s想要加入您的公會，請老大批准！',
		text_en = '#C0x5B545B#%s is requesting to join your union, please grant your approval!',
		text_vn = '#C0x5B545B%s muốn gia nhập bang hội của bạn. Làm ơn phê duyệt, hội trưởng!',
		text_kr = '#C0x5B545B#%s 님이 길드 가입을 신청했습니다!',
		text_pt = '#C0x5B545B#%s está solicitando filiação ao seu sindicato, por favor, conceda sua aprovação!',
		text_th = '#C0x5B545B#%s กำลังขอเข้าร่วมสหภาพของคุณ กรุณาให้การอนุมัติ!'
