	[1047] = {
		id = 1047,
		key = 'UnionIntro',
		text = 'Welcome to %s, let\'s build a new home',
		text_tw = '歡迎來到 %s，讓我們一起建設新家園',
		text_en = 'Welcome to %s, let\'s build a new home',
		text_vn = 'Chào mừng đến %s, hãy cùng nhau xây dựng một ngôi nhà mới.',
		text_kr = '%s 님, 환영합니다! 함께 노력해 성장합시다!',
		text_pt = 'Bem-vindo a %s, vamos construir uma nova casa',
		text_th = '“ยินดีต้อนรับสู่ %s มาสร้างบ้านใหม่กันเถอะ”'
	},
	[1048] = {
		id = 1048,
		key = 'LuckyCatDesc1',
		text = '#C0x5B545B#Everyone gets 5 chances,',
		text_tw = '#C0x5B545B#每個人都有5次機會，',
		text_en = '#C0x5B545B#Everyone gets 5 chances,',
		text_vn = '#C0x5B545B#Mỗi người có 5 cơ hội,',
		text_kr = '#C0x5B545B#모두 5회의 기회가 주어집니다.',
		text_pt = '#C0x5B545B#Todos têm 5 chances,',
		text_th = '#C0x5B545B#ทุกคนได้รับโอกาส 5 ครั้ง'
	},
	[1049] = {
		id = 1049,
		key = 'LuckyCatDesc2',
		text = 'More chances here#C0x5B545B#!',
		text_tw = '#C0x5B545B#有更多機會哦',
		text_en = 'More chances here#C0x5B545B#!',
		text_vn = 'Nhiều cơ hội hơn để nhận được Mảnh ghép và Z-Chiêu thức!',
		text_kr = '#C0x5B545B#더 많은 기회가 있습니다.',
		text_pt = 'Mais chances aqui#C0x5B545B#!',
		text_th = 'โอกาสมากขึ้นที่นี่#C0x5B545B#!'
	},
	[1050] = {
		id = 1050,
		key = 'pass_battle',
		text = '#C0x5B545B#As you\'ve displayed a heroic performance yesterday, you may skip this floor\'s battle and get full stars with the highest points. Continue? (You can only skip %s floors at most today)',
		text_tw = '#C0x5B545B#鑒於您昨日試煉的英勇表現，可直接跳過該層戰鬥，並獲得滿星和最高積分，是否繼續？（今日最多可跳過%s層）',
		text_en = '#C0x5B545B#As you\'ve displayed a heroic performance yesterday, you may skip this floor\'s battle and get full stars with the highest points. Continue? (You can only skip %s floors at most today)',
		text_vn = '#C0x5B545B#Vì màn thể hiện anh hùng của bạn trong thử thách ngày hôm qua, bạn có thể bỏ qua trận chiến này và nhận được đầy đủ sao và điểm số cao nhất. Bạn có muốn tiếp tục không? (Hôm nay bạn có thể bỏ qua tối đa %s màn)',
		text_kr = '#C0x5B545B#어제 시련에서의 활약을 통해 해당 층수 전투까지 스킵할 수 있게 되었으며, 최고 성급 및 최고 포인트를 획득했습니다. 계속하겠습니까? (오늘 최대 %s층까지 스킵 가능)',
		text_pt = '#C0x5B545B#Como você demonstrou uma performance heroica ontem, você pode pular a batalha deste andar e ganhar estrelas cheias com os pontos mais altos. Continuar? (Você só pode pular %s andares no máximo hoje)',
		text_th = '"#C0x5B545B#เนื่องจากคุณได้แสดงผลงานอันกล้าหาญเมื่อวานนี้ คุณจึงสามารถข้ามการต่อสู้ของชั้นนี้และรับดาวเต็มดวงด้วยคะแนนสูงสุด ดำเนินการต่อหรือไม่ (คุณสามารถข้ามชั้นได้มากที่สุดเพียง %s ชั้นเท่านั้นในวันนี้)'
	},
