		text_th = '#C0x5B545B#การต่อสู้อันยอดเยี่ยมของ Cross-Server Arena ได้รับการปรับปรุงใหม่แล้ว เข้ามาดูได้เลย'
	},
	[1099] = {
		id = 1099,
		key = 'ReunionInvite',
		text = '#C0x5B545B#Long time no see! I\'m #C0x5C9971#{name}.#C0x5B545B# Accept my invitation and help me complete the tasks! You will get rich rewards!#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_tw = '#C0x5B545B#好久不見~我是#C0x5C9971#{name}#C0x5B545B#,快接受我的邀請,幫助我完成任務一起領取獎勵吧~#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_en = '#C0x5B545B#Long time no see! I\'m #C0x5C9971#{name}.#C0x5B545B# Accept my invitation and help me complete the tasks! You will get rich rewards!#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_vn = 'Lâu rồi không gặp~ Mình là #{name}#, hãy nhận lời mời của mình, giúp mình hoàn thành nhiệm vụ và cùng nhận phần thưởng nhé~ #LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_kr = '#C0x5B545B#오랜만입니다~저는 #C0x5C9971#{name}#C0x5B545B#입니다. 어서 내 초대를 받아 미션 클리어를 도와주고 함께 보상을 수령하세요~#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_pt = '#C0x5B545B#Há quanto tempo! Eu sou #C0x5C9971#{name}.#C0x5B545B# Aceite meu convite e me ajude a completar as tarefas! Você ganhará recompensas valiosas!#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#',
		text_th = '#C0x5B545B#ไม่เจอกันนานเลยนะ ฉันคือ #C0x5C9971#{name}.#C0x5B545B# ยอมรับคำเชิญของฉันแล้วช่วยฉันทำภารกิจให้สำเร็จ! คุณจะได้รับรางวัลมากมาย!#LULreunion##Icity/adventure/clone_battle/imag_ljjr.png-182-54#'
	},
