		key = 'NewsCardInGroupDrawUp',
		text = '#C0x5B545B#Congratulations! #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#gets #C0xE69900#{star}#C0x5B545B# -star #C0xE77421##L10100##LULcard1#{card}#C0x5B545B# by choosed card draw and has increased its strength greatly!',
		text_tw = '#C0x5B545B#恭喜#C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#通過自選抽卡獲得了#C0xE69900#{star}#C0x5B545B#星#C0xE77421##L10100##LULcard1#{card}#C0x5B545B#，實力大幅增強！',
		text_en = '#C0x5B545B#Congratulations! #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#gets #C0xE69900#{star}#C0x5B545B# -star #C0xE77421##L10100##LULcard1#{card}#C0x5B545B# by choosed card draw and has increased its strength greatly!',
