		text_pt = '#C0x5B545B#Parabéns! #C0x5C9971##L10100##LULrole1#{name}#C0x5B545B#recebe #C0xE69900#{star}#C0x5B545B# -star #C0xE77421##L10100##LULcard1#{card}#C0x5B545B# por compra de cartas escolhida e aumentou muito sua força!',
