		text_kr = '#C0x5b545b#%s#C0x5b545b# 부활을 진행합니다. #C0x60C456#성격, 개체값, 노력치, 호감도#C0x5b545b# 외 나머지 육성 속성은 #C0xF76B45#초기 상태로 돌아갑니다#C0x5b545b#. 계속하겠습니까?',
		text_pt = '#C0x5b545b#%s#C0x5b545b# renascerá em breve. Além de #C0x60C456#Natureza, Valor Individual, Valor de Esforço e Amizade#C0x5b545b#, outras estatísticas retornarão ao seu estado inicial#C0x5b545b#. Você quer continuar?',
