		text = '#C0x5b545b# The selected Pokémon is about to be reborn and decomposed, the training resources used in its #C0x60C456# individual value, effort value and friendship level #C0x5b545b# will all be #C0xF76B45# gone #C0x5b545b#. Continue?',
		text_tw = '#C0x5b545b#即將重生並分解選中的精靈，#C0x60C456#個體值、努力值、好感度#C0x5b545b#的養成資源將會#C0xF76B45#損失#C0x5b545b#，是否繼續？',
		text_en = '#C0x5b545b# The selected Pokémon is about to be reborn and decomposed, the training resources used in its #C0x60C456# individual value, effort value and friendship level #C0x5b545b# will all be #C0xF76B45# gone #C0x5b545b#. Continue?',
		text_vn = '#C0x5b545b# Sắp trùng sinh cũng phân giải chọn trúng tinh linh, #C0x60C456# Cá thể giá trị, cố gắng giá trị, độ thiện cảm #C0x5b545b# Dưỡng thành tài nguyên sẽ #C0xF76B45# Tổn thất #C0x5b545b#, phải chăng tiếp tục?',
		text_kr = '#C0x5b545b#선택한 포켓몬을 부활 및 분해합니다. #C0x60C456#개체값, 노력치, 호감도#C0x5b545b#의 육성 자원을 #C0xF76B45#잃게 됩니다#C0x5b545b#. 계속하겠습니까?',
		text_pt = '#C0x5b545b# O Pokémon selecionado está prestes a renascer e se decompor, os recursos de treinamento usados em seu #C0x60C456# valor individual, valor de esforço e nível de amizade #C0x5b545b# serão todos #C0xF76B45# perdidos #C0x5b545b#. Continuar?',
		text_th = '#C0x5b545b# โปเกมอนที่ถูกเลือกกำลังจะเกิดใหม่และสลายตัว ทรัพยากรการฝึกฝนที่ใช้ใน #C0x60C456# มูลค่ารายบุคคล มูลค่าความพยายาม และระดับมิตรภาพ #C0x5b545b# จะหายไปทั้งหมด #C0xF76B45# #C0x5b545b# ดำเนินการต่อหรือไม่'
	},
