	[6776] = {
		id = 6776,
		key = 'tipsForSelectingMaterials',
		text = '#C0x5b545b#You\'ve used training materials for the selected Pokémon has training materials. It will #not be returned #C0x5b545b#if you use it to increase the star level. Are you sure you want to use this Pokémon?# C0x60C456#(Training materials can be returned through rebirth)',
		text_tw = '#C0x5b545b#所選精靈有養成材料投入，用作升星#C0xF76B45#消耗後將無返還，#C0x5b545b#是否確認添加材料？#C0x60C456#（可通過重生返還養成消耗）',
		text_en = '#C0x5b545b#You\'ve used training materials for the selected Pokémon has training materials. It will #not be returned #C0x5b545b#if you use it to increase the star level. Are you sure you want to use this Pokémon?# C0x60C456#(Training materials can be returned through rebirth)',
		text_vn = 'Pokémon đã được đầu tư nguyên liệu huấn luyện, dùng để nâng sao. #C0xF76B45#Sau khi sử dụng sẽ không được hoàn trả, #C0x5b545b#bạn có xác nhận thêm nguyên liệu không? #C0x60C456#(Có thể hoàn trả chi phí huấn luyện thông qua Tái sinh)',
		text_kr = '#C0x5b545b#선택한 포켓몬은 육성 재료가 투입되었습니다. 승급에 사용 시 #C0xF76B45#반환되지 않습니다. #C0x5b545b#정말 재료로 추가하겠습니까?#C0x60C456#(부활을 통해 육성 소모 반환)',
		text_pt = '#C0x5b545b#Você usou materiais de treinamento para o Pokémon selecionado tem materiais de treinamento. Ele #não será devolvido #C0x5b545b#se você usá-lo para aumentar o nível de estrela. Tem certeza de que deseja usar este Pokémon?# C0x60C456#(Materiais de treinamento podem ser devolvidos por meio do renascimento)',
		text_th = '#C0x5b545b#คุณได้ใช้วัสดุฝึกฝนสำหรับโปเกมอนที่เลือกแล้ว วัสดุฝึกฝนนั้นจะ #ไม่ส่งคืน #C0x5b545b# หากคุณใช้เพื่อเพิ่มระดับดาว คุณแน่ใจหรือไม่ว่าต้องการใช้โปเกมอนตัวนี้?# C0x60C456#(สามารถส่งคืนวัสดุฝึกฝนได้ผ่านการเกิดใหม่)'
	},
