		text_tw = '#C0x5B545B#所選道具養成等級大於1，#C0xF76B45#用於突破消耗後將無任何材料返回#C0x5B545B#，是否繼續選擇該道具？#C0x60C456#（可通過重生返回養成材料）',
		text_en = '#C0x5B545B#The training level of the selection item is more than 1, #C0xF76B45# no materials will be returned if it is used for breakthough#C0x5B545B#. Do you want to continue?# C0x60C456#(Training materials can be returned through rebirth)',
		text_vn = 'Mức độ nuôi dưỡng của vật phẩm đã chọn lớn hơn 1. Sử dụng nó để đột phá sẽ không có bất kỳ nguyên liệu nào được trả lại. Bạn có muốn tiếp tục không?',
		text_kr = '#C0x5B545B#선택한 아이템 육성 레벨이 1보다 높습니다. #C0xF76B45#돌파에 사용해 소모 시 어떤 재료도 반환하지 않습니다#C0x5B545B#. 해당 아이템을 계속 선택하겠습니까?#C0x60C456#(부활을 통해 육성 재료 반환 가능)',
		text_pt = '#C0x5B545B#O nível de treinamento do item selecionado é maior que 1, #C0xF76B45# nenhum material será devolvido se for usado para avanço#C0x5B545B#. Você quer continuar?# C0x60C456#(Materiais de treinamento podem ser devolvidos por meio do renascimento)',
		text_th = '#C0x5B545B# ระดับการฝึกของรายการที่เลือกมีมากกว่า 1, #C0xF76B45# จะไม่มีการคืนวัสดุใดๆ หากใช้เพื่อการฝ่าฟัน#C0x5B545B# คุณต้องการดำเนินการต่อหรือไม่? # C0x60C456# (สามารถคืนวัสดุการฝึกได้ผ่านการเกิดใหม่)'
	},
	[7016] = {
		id = 7016,
		key = 'heldItemAdvanceDressTip',
		text = '#C0x5B545B#The selected item is currently worn by %s#C0x5B545B#. Are you sure you want to use it? (#C0x60C456#The item will be removed if you proceed#C0x5B545B#)',
		text_tw = '#C0x5B545B#所選道具已被%s#C0x5B545B#穿戴，是否繼續用於本次消耗？（#C0x60C456#確認後該道具將被脫下#C0x5B545B#）',
		text_en = '#C0x5B545B#The selected item is currently worn by %s#C0x5B545B#. Are you sure you want to use it? (#C0x60C456#The item will be removed if you proceed#C0x5B545B#)',
		text_vn = 'Đồ vật đã được trang bị %s. Bạn có muốn tiếp tục sử dụng và tiêu hao nó không? (#C0x60C456#Đồ vật sẽ được tháo ra sau khi xác nhận#C0x5B545B#)',
		text_kr = '#C0x5B545B#선택한 아이템이 %s#C0x5B545B#에게 착용되어 있습니다. 이번 소모에 계속해서 사용하겠습니까?(#C0x60C456#확인 시 해당 아이템이 해제됨#C0x5B545B#)',
		text_pt = '#C0x5B545B#O item selecionado está sendo usado por %s#C0x5B545B#. Tem certeza de que deseja usá-lo? (#C0x60C456#O item será removido se você prosseguir#C0x5B545B#)',
