	[7077] = {
		id = 7077,
		key = 'chooseNatureText',
		text = '#C0x5b545b#This Pokémon\'s type will switch from #I%s-60-60##C0x5b545b# to #I%s-60-60##C0x5b545b# as the team aura has taken effect. After switching it will be effective in all formation interface. Do you want to continue?',
		text_tw = '#C0x5b545b#該精靈在隊伍光環內生效屬性即將由#I%s-60-60##C0x5b545b#切換為#I%s-60-60##C0x5b545b#，切換後所有編隊介面內生效，是否繼續？',
		text_en = '#C0x5b545b#This Pokémon\'s type will switch from #I%s-60-60##C0x5b545b# to #I%s-60-60##C0x5b545b# as the team aura has taken effect. After switching it will be effective in all formation interface. Do you want to continue?',
		text_vn = '#C0x5b545b# Thuộc tính hiệu lực trong Aura đội ngũ của Pokémon này từ #I%s-60-60##C0x5b545b# chuyển thành #I%s-60-60##C0x5b545b#, sau khi chuyển đổi sẽ hiệu lực trong tất cả giao diện lập đội, tiếp tục không?',
		text_kr = '#C0x5b545b#해당 포켓몬의 팀 오라 유효 타입 #I%s-60-60##C0x5b545b#→#I%s-60-60##C0x5b545b# 전환이 이루어집니다. 전환 후에는 모든 진형 대상에게 적용됩니다. 계속하겠습니까?',
		text_pt = '#C0x5b545b#O tipo deste Pokémon mudará de #I%s-60-60##C0x5b545b# para #I%s-60-60##C0x5b545b# conforme a aura da equipe tiver efeito. Após a troca, ela será efetiva em todas as interfaces de formação. Você quer continuar?',
		text_th = '#C0x5b545b#ประเภทของโปเกมอนตัวนี้จะเปลี่ยนจาก #I%s-60-60##C0x5b545b# เป็น #I%s-60-60##C0x5b545b# เนื่องจากออร่าของทีมมีผล หลังจากเปลี่ยนแล้ว จะมีผลกับอินเทอร์เฟซการจัดรูปแบบทั้งหมด คุณต้องการดำเนินการต่อหรือไม่'
