	[7203] = {
		id = 7203,
		key = 'randomTowerCanJumpTips1',
		text = '#F50##C0x5b545b#Based on your previous performance and current level, you can crush all the way to the previous battle of level #C0x60C456#%s room %s#C0x5b545b#. Select [Through high-rise] to instantly proceed to level #C0x60C456#%s room %s#C0x5b545b#.',
		text_tw = '#F50##C0x5b545b#根據您之前的表現和當前等級，您可以碾壓直到#C0x60C456#%s層房間%s#C0x5b545b#之前的戰鬥，選擇【直通高層】可以快速到達#C0x60C456#%s層房間%s#C0x5b545b#。',
		text_en = '#F50##C0x5b545b#Based on your previous performance and current level, you can crush all the way to the previous battle of level #C0x60C456#%s room %s#C0x5b545b#. Select [Through high-rise] to instantly proceed to level #C0x60C456#%s room %s#C0x5b545b#.',
		text_vn = 'Dựa trên thành tích trước đây và cấp độ hiện tại, bạn có thể nghiền nát các trận chiến cho đến phòng tầng %s %s. Chọn [Đi thẳng lên tầng cao] cho phép bạn nhanh chóng đến phòng tầng %s %s.',
		text_kr = '#F50##C0x5b545b#지난 결과와 현재 레벨에 따라 #C0x60C456#%s층 방 %s#C0x5b545b#의 전투까지 진압할 수 있습니다. [고층 직통] 선택 시 빠르게 #C0x60C456#%s층 방 %s#C0x5b545b#에 도달할 수 있습니다.',
		text_pt = '#F50##C0x5b545b#Com base no seu desempenho anterior e nível atual, você pode esmagar todo o caminho até a batalha anterior do nível #C0x60C456#%s sala %s#C0x5b545b#. Selecione [Através de arranha-céus] para prosseguir instantaneamente para o nível #C0x60C456#%s sala %s#C0x5b545b#.',
		text_th = '#F50##C0x5b545b# ขึ้นอยู่กับผลงานก่อนหน้าและเลเวลปัจจุบันของคุณ คุณสามารถบุกทะลวงไปจนถึงการต่อสู้ก่อนหน้าของห้อง %s#C0x60C456#%s ได้ เลือก [ผ่านตึกสูง] เพื่อไปยังห้อง %s#C0x5b545b# ของ #C0x60C456#%s ทันที'
	},
