		text_kr = '#C0x5B545B#이미 #C0xF76B45##L10#2#C0xFF5B545B##L0#개의 룬스톤을 배치했습니다. 소모 시 #C0xF76B45##L10#1개의 새 룬스톤으로 바꿀 수 있습니다#C0xFF5B545B##L0#(룬스톤을 이미 강화한 경우, 무료로 강화 재료 반환). 정말 바꾸겠습니까?',
		text_pt = '#C0x5B545B# foi colocada #C0xF76B45##L10#2#C0xFF5B545B##L0# runestones, após o consumo #C0xF76B45##L10# só pode ser substituída por 1 nova runestone #C0xFF5B545B##L0# (como Runestone Se ela foi fortalecida, os materiais reforçados serão devolvidos gratuitamente.) As substituições são confirmadas?',
		text_th = '#C0x5B545B# ได้ถูกวางรูนสโตน #C0xF76B45##L10#2#C0xFF5B545B##L0# แล้ว หลังจากใช้รูนสโตน #C0xF76B45##L10# ไปแล้ว จะสามารถเปลี่ยนได้ด้วยรูนสโตน #C0xFF5B545B##L0# ใหม่เพียง 1 อันเท่านั้น (เช่นเดียวกับรูนสโตน หากได้รับการเสริมความแข็งแกร่ง วัสดุเสริมความแข็งแกร่งจะถูกส่งคืนโดยไม่มีค่าใช้จ่าย) มีการยืนยันการเปลี่ยนแล้วหรือยัง?'
