	[7457] = {
		id = 7457,
		key = 'fishGameStartIsAutoFishing',
		text = 'During the fishing contest, the fish caught in this scene are not counted as points in the competition. Are the consumption times and automatic fishing of bait determined?',
		text_tw = '釣魚大賽進行中，本場景釣到的魚不計入大賽積分，確定消耗次數和魚餌自動釣魚？',
		text_en = 'During the fishing contest, the fish caught in this scene are not counted as points in the competition. Are the consumption times and automatic fishing of bait determined?',
		text_vn = 'Cuộc thi câu cá đang diễn ra. Cá câu được ở khu vực này sẽ không được tính vào điểm thi đấu. Xác nhận số lần sử dụng và mồi để câu cá tự động?',
		text_kr = '낚시대회 진행 중입니다. 본 장소에서 낚은 물고기는 대회 포인트에 반영되지 않습니다. 정말 횟수와 미끼를 소모해 자동 낚시를 진행하겠습니까?',
		text_pt = 'Durante a competição de pesca, os peixes capturados nesta cena não são contabilizados como pontos na competição. Os tempos de consumo e pesca automática de iscas são determinados?',
		text_th = 'ระหว่างการแข่งขันตกปลา ปลาที่จับได้ในฉากนี้จะไม่นับเป็นคะแนนในการแข่งขัน เวลาที่ใช้และการตกปลาอัตโนมัติถูกกำหนดหรือไม่'
	},
	[7458] = {
