	[7460] = {
		id = 7460,
		key = 'gemUpNum',
		text = '#C0x5B545B# has been placed #C0xF76B45##L10#3#C0xFF5B545B##L0# runestones, after consumption #C0xF76B45##L10# can be replaced with 2 new runestones #C0xFF5B545B##L0# (if runestones have been Reinforcement, the reinforcement materials will be returned free of charge), do you confirm the replacement?',
		text_tw = '#C0x5B545B#已放置#C0xF76B45##L10#3#C0xFF5B545B##L0#個符石，消耗後#C0xF76B45##L10#可以置換為2個新的符石#C0xFF5B545B##L0#（如符石已強化，則免費返還強化材料），是否確認置換？',
		text_en = '#C0x5B545B# has been placed #C0xF76B45##L10#3#C0xFF5B545B##L0# runestones, after consumption #C0xF76B45##L10# can be replaced with 2 new runestones #C0xFF5B545B##L0# (if runestones have been Reinforcement, the reinforcement materials will be returned free of charge), do you confirm the replacement?',
		text_vn = 'Đã đặt #C0xF76B45##L10#3#C0xFF5B545B##L0# Mảnh ghép. Sau khi sử dụng, chúng có thể được đổi thành 2 Mảnh ghép mới #C0xFF5B545B##L0#(Nếu Mảnh ghép đã được cường hóa, nguyên liệu cường hóa sẽ được hoàn trả miễn phí). Xác nhận trao đổi?',
		text_kr = '#C0x5B545B#이미 #C0xF76B45##L10#3#C0xFF5B545B##L0#개의 룬스톤을 배치했습니다. 소모 시 #C0xF76B45##L10#2개의 새 룬스톤으로 바꿀 수 있습니다#C0xFF5B545B##L0#(룬스톤을 이미 강화한 경우, 무료로 강화 재료 반환). 정말 바꾸겠습니까?',
		text_pt = '#C0x5B545B# foram colocadas #C0xF76B45##L10#3#C0xFF5B545B##L0# runas, após o consumo #C0xF76B45##L10# podem ser substituídas por 2 novas runas #C0xFF5B545B##L0# (se as runas foram Reforçadas, os materiais de reforço serão devolvidos gratuitamente), você confirma a substituição?',
		text_th = '#C0x5B545B# ได้ถูกวางรูนสโตน #C0xF76B45##L10#3#C0xFF5B545B##L0# แล้ว หลังจากใช้รูนสโตน #C0xF76B45##L10# ไปแล้ว สามารถแทนที่ด้วยรูนสโตนใหม่ 2 รูนสโตน #C0xFF5B545B##L0# ได้ (หากรูนสโตนได้รับการเสริมกำลังแล้ว วัสดุเสริมกำลังจะถูกส่งคืนโดยไม่มีค่าใช้จ่าย) คุณยืนยันการเปลี่ยนใหม่หรือไม่'
	},
