	[7696] = {
		id = 7696,
		key = 'gymGateDesc',
		text = '#LOC0x5A545B##F38##C0xFEFDEC#Challenge #C0xAEE97E#any#C0xFEFDEC# difficulty, get Badge material \nAfter clear all difficulties, challenge to become#C0xECB72A# server Honor Gym Leader!',
		text_tw = '#LOC0x5A545B##F38##C0xFEFDEC#挑戰#C0xAEE97E#任意#C0xFEFDEC#道館難度，獲取徽章的強化材料\n成功通過所有難度後，可挑戰成為#C0xECB72A#本服榮譽館主',
		text_en = '#LOC0x5A545B##F38##C0xFEFDEC#Challenge #C0xAEE97E#any#C0xFEFDEC# difficulty, get Badge material \nAfter clear all difficulties, challenge to become#C0xECB72A# server Honor Gym Leader!',
		text_vn = 'Thách thức bất kỳ độ khó nào của phòng Gym để nhận được nguyên liệu cường hóa huy hiệu.\nHoàn thành thành công tất cả các độ khó cho phép bạn thách đấu để trở thành Nhà vô địch danh dự của máy chủ.',
		text_kr = '#LOC0x5A545B##F38##C0xFEFDEC#도전#C0xAEE97E#임의#C0xFEFDEC#도관난이도 획득 배지의 강화 재료\n이 모든 난이도를 클리어하면 #C0xECB72A#본 서버 명예관장이 됩니다',
		text_pt = '#LOC0x5A545B##F38##C0xFEFDEC#Desafio #C0xAEE97E#qualquer#C0xFEFDEC# dificuldade, receba material de distintivo nDepois de superar todas as dificuldades, desafie para se tornar o#C0xECB72A# Líder de Ginásio de Honra do servidor!',
		text_th = '#LOC0x5A545B##F38##C0xFEFDEC#Challenge #C0xAEE97E#any#C0xFEFDEC# รับวัสดุป้าย nหลังจากผ่านความยากทั้งหมดแล้ว ท้าทายเพื่อเป็นผู้นำยิมเกียรติยศในเซิร์ฟเวอร์ #C0xECB72A#!'
	},
