	[7900] = {
		id = 7900,
		key = 'double11GainDisplayTitle',
		text = 'Congratulations! You\'ve completed Red Pack Rain. Here\'s a coupon for you. Go to the bottom left of the screen to use it.',
		text_tw = '恭喜你完成了天降紅包小遊戲，送你一張獎券，在本活動介面左下角使用喔！',
		text_en = 'Congratulations! You\'ve completed Red Pack Rain. Here\'s a coupon for you. Go to the bottom left of the screen to use it.',
		text_vn = 'Chúc mừng bạn đã hoàn thành trò chơi nhỏ lì xì rơi từ trời! Bạn đã nhận được một phiếu quà tặng. Hãy sử dụng nó ở góc dưới bên trái của giao diện sự kiện này!',
		text_kr = '축하합니다. 보너스 미니게임을 완료해 쿠폰 1장을 드립니다. 해당 이벤트 화면 좌측 하단에서 사용할 수 있습니다!',
		text_pt = 'Parabéns! Você completou Red Pack Rain. Aqui está um cupom para você. Vá para o canto inferior esquerdo da tela para usá-lo.',
		text_th = 'ขอแสดงความยินดี! คุณทำภารกิจ Red Pack Rain สำเร็จแล้ว นี่คือคูปองสำหรับคุณ ไปที่มุมซ้ายล่างของหน้าจอเพื่อใช้คูปอง'
	},
