	[7903] = {
		id = 7903,
		key = 'double11AwardTips2',
		text = '#C0x5B545B#Your number is %d. Sorry it\'s not any winning number. Better luck next time!',
		text_tw = '#C0x5B545B#你抽到的號碼為%d，沒有與本場任何獎勵展示的號碼對應，很遺憾，但是下次運氣會更好的！',
		text_en = '#C0x5B545B#Your number is %d. Sorry it\'s not any winning number. Better luck next time!',
		text_vn = '#C0x5B545B#Số bạn rút được là %d, không trùng khớp với bất kỳ số trúng thưởng nào được hiển thị trong vòng này. Rất tiếc, nhưng chúc bạn may mắn hơn lần sau!',
		text_kr = '#C0x5B545B#귀하의 번호는 %d이며, 아쉽게도 이번 경기의 번호와 맞지 않습니다. 다음에는 운이 더 좋길 바라요!',
		text_pt = '#C0x5B545B#Seu número é %s. Desculpe, não é nenhum número ganhador. Mais sorte na próxima!',
		text_th = '#C0x5B545B#หมายเลขของคุณคือ %s ขออภัย ไม่ใช่หมายเลขที่ถูกรางวัล ขอให้โชคดีในครั้งหน้า!'
	},
	[7904] = {
		id = 7904,
		key = 'double11AwardTips3',
		text = '#C0x5B545B#You can\'t redeem as you didn\'t participate in Red Pack Rain. Don\'t miss out the next time!',
		text_tw = '#C0x5B545B#本場你並沒有參加天降紅包活動，因此沒有獲得兌獎機會，好可惜，下次要準時參加呀！',
		text_en = '#C0x5B545B#You can\'t redeem as you didn\'t participate in Red Pack Rain. Don\'t miss out the next time!',
		text_vn = 'Rất tiếc, bạn đã bỏ lỡ sự kiện lì xì bất ngờ lần này, vì vậy bạn không có cơ hội nhận thưởng! Hãy nhớ tham gia đúng giờ vào lần sau nhé!',
		text_kr = '아쉽게도 #C0x5B545B#이번 회차 보너스 미니게임을 참여하지 않아 쿠폰 교환 기회를 얻지 못했습니다. 다음에는 제때 참여해 주세요!',
		text_pt = '#C0x5B545B#Você não pode resgatar porque não participou do Red Pack Rain. Não perca na próxima vez!',
		text_th = '#C0x5B545B#คุณไม่สามารถแลกรับได้เนื่องจากคุณไม่ได้เข้าร่วมกิจกรรม Red Pack Rain อย่าพลาดโอกาสครั้งหน้า!'
	},
