	[7910] = {
		id = 7910,
		key = 'onSwitchChangeShape',
		text = 'The first switch costs #C0xF76B45#%d#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#(#C0x5C9970#No more cost for more switches of the same Pokémon. #C0xF76B45#But switches of new Pokémon of the same series still cost Diamonds#C0x5B545B#). Continue? (All the development will be inherited after the switching.)',
		text_tw = '首次切換需要消耗#C0xF76B45#%d#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#（#C0x5C9970#同一精靈後續切換將無任何消耗；#C0xF76B45#但新的同系列精靈切換時仍需要消耗同樣鉆石#C0x5B545B#），是否繼續？(切換形態後，所有養成將完全繼承)',
		text_en = 'The first switch costs #C0xF76B45#%d#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#(#C0x5C9970#No more cost for more switches of the same Pokémon. #C0xF76B45#But switches of new Pokémon of the same series still cost Diamonds#C0x5B545B#). Continue? (All the development will be inherited after the switching.)',
		text_vn = 'Lần chuyển đổi đầu tiên cần tiêu hao #C0xF76B45#%d#Icommon/icon/icon_diamond.png-56-56##C0x5B545B# (#C0x5C9970#Các lần chuyển đổi tiếp theo cho cùng một Pokémon sẽ không mất phí; #C0xF76B45#tuy nhiên, chuyển đổi sang một Pokémon mới cùng loại vẫn cần tiêu hao số Kim Cương tương tự#C0x5B545B#), có tiếp tục không? (Sau khi chuyển đổi hình dạng, tất cả các chỉ số nuôi dưỡng sẽ được kế thừa hoàn toàn)',
		text_kr = '첫 교체 시 #C0xF76B45#%d#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#을(를) 소모합니다(이후 #C0x5C9970#같은 포켓몬으로 교체 시 소모 값이 없습니다. #C0xF76B45#하지만 같은 계열의 포켓몬으로 교체 시 동일한 다이아를 소모합니다#C0x5B545B#). 진행하시겠습니까? (형태 교체 후 모든 트레이닝을 계승합니다)',
		text_pt = 'A primeira troca custa #C0xF76B45#%s#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#(#C0x5C9970#Não há mais custo para mais trocas do mesmo Pokémon. #C0xF76B45#Mas trocas de novos Pokémon da mesma série ainda custam Diamantes#C0x5B545B#). Continuar? (Todo o desenvolvimento será herdado após a troca.)',
		text_th = 'การสลับครั้งแรกมีค่าใช้จ่าย #C0xF76B45#%s#Icommon/icon/icon_diamond.png-56-56##C0x5B545B#(#C0x5C9970#ไม่มีค่าใช้จ่ายเพิ่มเติมสำหรับการสลับโปเกมอนตัวเดียวกัน #C0xF76B45#แต่การสลับโปเกมอนตัวใหม่ในซีรีส์เดียวกันยังคงมีค่าใช้จ่ายเป็นเพชร#C0x5B545B#) ดำเนินการต่อหรือไม่ (การพัฒนาทั้งหมดจะสืบทอดหลังจากสลับ)'
	},
