	[7933] = {
		id = 7933,
		key = 'gymReset',
		text = '#C0x5B545B#All #C0x3C8B99#Gym Dungeon#C0x5B545B#, #C0x3C8B99#Honorary Gym Leader#C0x5B545B# and #C0x3C8B99#Challenge Buff#C0x5B545B# are about to reset. New challenges are waiting!',
		text_tw = '#C0x5B545B#所有#C0x3C8B99#道館副本#C0x5B545B#，#C0x3C8B99#榮譽館主#C0x5B545B#及#C0x3C8B99#挑戰加成#C0x5B545B#開始重置，新的挑戰即將開始！',
		text_en = '#C0x5B545B#All #C0x3C8B99#Gym Dungeon#C0x5B545B#, #C0x3C8B99#Honorary Gym Leader#C0x5B545B# and #C0x3C8B99#Challenge Buff#C0x5B545B# are about to reset. New challenges are waiting!',
		text_vn = 'Tất cả các thử thách phòng Gym, các Nhà vô địch danh dự và phần thưởng thử thách sẽ được đặt lại. Những thử thách mới sắp bắt đầu!',
		text_kr = '#C0x5B545B#모든 #C0x3C8B99#체육관 던전#C0x5B545B#, #C0x3C8B99#명예 관장#C0x5B545B# 및 #C0x3C8B99#도전 보너스#C0x5B545B#가 초기화됩니다. 새로운 도전이 곧 시작합니다!',
		text_pt = '#C0x5B545B#Todos os #C0x3C8B99#Gym Dungeon#C0x5B545B#, #C0x3C8B99#Honorary Gym Leader#C0x5B545B# e #C0x3C8B99#Challenge Buff#C0x5B545B# estão prestes a reiniciar. Novos desafios estão esperando!',
		text_th = '#C0x5B545B#C0x3C8B99#Gym Dungeon#C0x5B545B# ทั้งหมด, #C0x3C8B99#Honorary Gym Leader#C0x5B545B# และ #C0x3C8B99#Challenge Buff#C0x5B545B# กำลังจะรีเซ็ต ความท้าทายใหม่กำลังรออยู่!'
	},
