	},
	[7987] = {
		id = 7987,
		key = 'snowBallGuide1',
		text = 'The mini game is #C0xF76B45#is controlled with joysticks. #C0x5B545B#Tap#C0xF76B45# anywhere#C0x5B545B# on the screen to operate.',
		text_tw = '小遊戲為#C0xF76B45#搖桿滑動操作，#C0x5B545B#在螢幕中#C0xF76B45#任意位置#C0x5B545B#都可進行操作',
		text_en = 'The mini game is #C0xF76B45#is controlled with joysticks. #C0x5B545B#Tap#C0xF76B45# anywhere#C0x5B545B# on the screen to operate.',
		text_vn = 'Minigame sử dụng thao tác vuốt cần điều khiển #C0xF76B45#, có thể thao tác ở #C0xF76B45#bất kỳ vị trí nào#C0x5B545B# trên màn hình.',
		text_kr = '미니 게임은 #C0xF76B45#컨트롤 조작 방식이며, #C0x5B545B#스크린의 #C0xF76B45#아무 위치에서 #C0x5B545B#조작할 수 있습니다',
		text_pt = 'O minijogo #C0xF76B45# é controlado com joysticks. #C0x5B545B#Toque#C0xF76B45# em qualquer lugar#C0x5B545B# na tela para operar.',
		text_th = 'มินิเกมนี้คือ #C0xF76B45# ซึ่งควบคุมด้วยจอยสติ๊ก #C0x5B545B# แตะ #C0xF76B45# ที่ไหนก็ได้ #C0x5B545B# บนหน้าจอเพื่อควบคุม'
	},
	[7988] = {
		id = 7988,
		key = 'snowBallGuide2',
		text = 'The game ends when time is up. The longer one #C0xF76B45#survives#C0x5B545B#, the more point bonuses he gets.#C0xF76B45#',
		text_tw = '遊戲時間歸零遊戲結束，而#C0xF76B45#存活的時間#C0x5B545B#越長，越能獲得#C0xF76B45#可觀的積分加成哦',
		text_en = 'The game ends when time is up. The longer one #C0xF76B45#survives#C0x5B545B#, the more point bonuses he gets.#C0xF76B45#',
		text_vn = 'Thời gian trò chơi về không, trò chơi kết thúc. Thời gian #C0xF76B45#sinh tồn#C0x5B545B# càng lâu, bạn càng nhận được #C0xF76B45#thưởng điểm đáng kể!',
		text_kr = '게임 시간이 경과되면 게임이 종료되며, #C0xF76B45#생존 시간#C0x5B545B#이 길수록 #C0xF76B45#더 많은 포인트 보너스를 획득할 수 있습니다',
		text_pt = 'O jogo termina quando o tempo acaba. Quanto mais tempo alguém #C0xF76B45#sobrevive#C0x5B545B#, mais bônus de pontos ele ganha.#C0xF76B45#',
		text_th = 'เกมจะจบลงเมื่อเวลาหมดลง ยิ่ง #C0xF76B45# รอดชีวิต #C0x5B545B# ได้นานเท่าไร เขาก็จะยิ่งได้รับโบนัสคะแนนมากขึ้นเท่านั้น #C0xF76B45#'
	},
	[7989] = {
		id = 7989,
		key = 'snowBallGuide3',
		text = 'Meowth Tank fires Snowball. If you are hit by a #C0xF76B45#falling snowball#C0x5B545B#, your #C0xF76B45#HP#C0x5B545B# will lose. Be careful out there!',
		text_tw = '喵喵坦克會噴射雪球，若被#C0xF76B45#掉落的雪球#C0x5B545B#砸中，會#C0xF76B45#損失生命值，#C0x5B545B#要小心躲避',
		text_en = 'Meowth Tank fires Snowball. If you are hit by a #C0xF76B45#falling snowball#C0x5B545B#, your #C0xF76B45#HP#C0x5B545B# will lose. Be careful out there!',
		text_vn = 'Meowth Tank sẽ bắn ra những quả cầu tuyết. Nếu bị #C0xF76B45#quả cầu tuyết rơi xuống#C0x5B545B# trúng, bạn sẽ #C0xF76B45#mất máu.#C0x5B545B# Hãy cẩn thận tránh né.',
		text_kr = '냐옹이 탱크는 스노우볼을 발사합니다. 만약 #C0xF76B45#떨어지는 스노우볼#C0x5B545B#에 맞으면 #C0xF76B45#HP를 잃으니 #C0x5B545B#조심하세요',
		text_pt = 'Meowth Tank atira Snowball. Se você for atingido por uma #C0xF76B45#bola de neve caindo#C0x5B545B#, seu #C0xF76B45#HP#C0x5B545B# perderá. Tenha cuidado lá fora!',
		text_th = 'Meowth Tank ยิง Snowball หากคุณโดน #C0xF76B45#falling snowball#C0x5B545B# #C0xF76B45#HP#C0x5B545B# ของคุณจะแพ้ ระวังตัวให้ดี!'
	},
	[7990] = {
		id = 7990,
		key = 'snowBallGuide4',
		text = 'Delibird delivers gift boxes. #C0xF76B45#Pick up the boxes#C0x5B545B# and you\'ll get #C0xF76B45#point bonuses#C0x5B545B#. Gift boxes #C0xF76B45#expire soon#C0x5B545B#, so make sure you get them in time!',
		text_tw = '信使鳥會投擲禮盒，#C0xF76B45#拾取禮盒#C0x5B545B#可以獲得#C0xF76B45#積分加成，#C0x5B545B#只是禮盒#C0xF76B45#存留時間有限，#C0x5B545B#要盡快取得',
		text_en = 'Delibird delivers gift boxes. #C0xF76B45#Pick up the boxes#C0x5B545B# and you\'ll get #C0xF76B45#point bonuses#C0x5B545B#. Gift boxes #C0xF76B45#expire soon#C0x5B545B#, so make sure you get them in time!',
		text_vn = 'Chim chim messenger sẽ ném hộp quà. #C0xF76B45#Nhặt hộp quà#C0x5B545B# sẽ nhận được #C0xF76B45#thêm điểm thưởng, #C0x5B545B#nhưng hộp quà #C0xF76B45#chỉ tồn tại trong thời gian giới hạn, #C0x5B545B#hãy nhanh chóng lấy chúng!',
		text_kr = '딜리버드는 선물함을 떨굽니다. #C0xF76B45#선물함#C0x5B545B#을 주우면 #C0xF76B45#포인트 보너스를 획득합니다. #C0x5B545B#선물함#C0xF76B45#은 금방 사라지니 #C0x5B545B#최대한 빨리 획득하세요',
		text_pt = 'A Delibird entrega caixas de presente. #C0xF76B45#Pegue as caixas#C0x5B545B# e você ganhará #C0xF76B45#bônus de pontos#C0x5B545B#. As caixas de presente #C0xF76B45#expiram em breve#C0x5B545B#, então certifique-se de recebê-las a tempo!',
		text_th = 'Delibird จัดส่งกล่องของขวัญ #C0xF76B45#หยิบกล่อง#C0x5B545B# แล้วคุณจะได้รับโบนัส #C0xF76B45#คะแนน#C0x5B545B# กล่องของขวัญ #C0xF76B45# จะหมดอายุเร็วๆ นี้#C0x5B545B# ดังนั้นอย่าลืมรับกล่องให้ทันเวลา!'
	},
