	[8261] = {
		id = 8261,
		key = 'preventFraudChatTips',
		text = 'Dear trainer, please don\'t believe in any advertising information such as recharge discounts on World Channels, and be wary of the behavior of buying accounts in private chats. These are all online scams! If you encounter any suspicious information, please feel free to contact customer service for feedback, wish you enjoy our game!',
		text_tw = '尊敬的訓練家，請不要相信任何世界頻道充值折扣等廣告資訊，警惕小號私聊購買賬號的行為，這些都是網絡詐騙！如遇到任何可疑資訊請隨時與客服聯系反饋，祝您遊戲愉快！',
		text_en = 'Dear trainer, please don\'t believe in any advertising information such as recharge discounts on World Channels, and be wary of the behavior of buying accounts in private chats. These are all online scams! If you encounter any suspicious information, please feel free to contact customer service for feedback, wish you enjoy our game!',
		text_vn = 'Huấn luyện viên kính mến, vui lòng đừng tin bất kỳ quảng cáo nào trên kênh thế giới về giảm giá nạp tiền, v.v. Hãy cảnh giác với hành vi nhắn tin riêng tư của các tài khoản nhỏ để mua tài khoản, đây đều là lừa đảo trực tuyến! Nếu gặp bất kỳ thông tin đáng ngờ nào, vui lòng liên hệ với bộ phận chăm sóc khách hàng để phản hồi bất cứ lúc nào. Chúc bạn chơi game vui vẻ!',
		text_kr = '존경하는 트레이너님, 세계 채널의 충전 할인 등 광고 정보를 절대 믿지 마십시오. 작은 계정이 개인적으로 계정 구매를 제안하는 행위에 주의하십시오. 이러한 행위는 모두 온라인 사기입니다! 의심스러운 정보가 있으면 언제든지 고객센터에 문의하여 피드백을 제공하십시오. 즐거운 게임 되세요!',
		text_pt = 'Caro treinador, por favor, não acredite em nenhuma informação publicitária, como descontos de recarga em Canais Mundiais, e tenha cuidado com o comportamento de comprar contas em chats privados. Tudo isso são golpes online! Se você encontrar alguma informação suspeita, sinta-se à vontade para entrar em contato com o atendimento ao cliente para obter feedback, esperamos que você aproveite nosso jogo!',
		text_th = 'เรียนผู้ฝึกสอนทุกท่าน โปรดอย่าเชื่อข้อมูลโฆษณาใดๆ เช่น ส่วนลดการเติมเงินใน World Channels และระวังพฤติกรรมการซื้อบัญชีในแชทส่วนตัว สิ่งเหล่านี้ล้วนเป็นการหลอกลวงทางออนไลน์! หากคุณพบข้อมูลที่น่าสงสัย โปรดติดต่อฝ่ายบริการลูกค้าเพื่อขอคำติชม ขอให้คุณสนุกกับเกมของเรา!'
	},
	[8262] = {
		id = 8262,
		key = 'preventFraudPosterTitle',
		text = '#Pfont/youmi1.ttf#Be vigilant and beware of account fraud',
		text_tw = '#Pfont/youmi1.ttf#提高警惕,謹防賬號詐騙',
		text_en = '#Pfont/youmi1.ttf#Be vigilant and beware of account fraud',
		text_vn = '#Pfont/youmi1.ttf#Cảnh giác cao độ, phòng tránh lừa đảo tài khoản',
		text_kr = '#Pfont/youmi1.ttf#주의하십시오. 계정 사기로부터 조심하세요.',
		text_pt = '#Pfont/youmi1.ttf#Fique atento e tome cuidado com fraudes de conta',
		text_th = '#Pfont/youmi1.ttf#โปรดระวังการฉ้อโกงบัญชี'
	},
	[8263] = {
		id = 8263,
		key = 'preventFraudPosterDes1',
		text = '#Pfont/youmi1.ttf#Usage:\n#Pfont/youmi.ttf#PM you and want to buy our account, but without using the formal platform! \nPrice is falsely high, with the intent to lure a deal! \nTrading cash withdrawal, but also cheating fees!',
		text_tw = '#Pfont/youmi1.ttf#慣用手法：\n#Pfont/youmi.ttf#私聊買號，不走正規平臺！\n出價虛高，意圖引誘交易！\n交易提現，還要騙手續費！',
		text_en = '#Pfont/youmi1.ttf#Usage:\n#Pfont/youmi.ttf#PM you and want to buy our account, but without using the formal platform! \nPrice is falsely high, with the intent to lure a deal! \nTrading cash withdrawal, but also cheating fees!',
		text_vn = '#Pfont/youmi1.ttf#Chiến thuật thường dùng:\n#Pfont/youmi.ttf#Mua tài khoản qua tin nhắn riêng, không thông qua nền tảng chính thức!\nĐặt giá cao hơn thực tế để dụ người mua giao dịch!\nLừa thêm phí trong quá trình rút tiền!',
		text_kr = '#Pfont/youmi1.ttf#일반적인 수법:\n#Pfont/youmi.ttf#정식 플랫폼을 거치지 않고 개인적으로 계정을 구매합니다!\n가격을 부풀려 거래를 유도합니다!\n출금 시 수수료를 추가로 요구합니다!',
		text_pt = '#Pfont/youmi1.ttf#Uso:n#Pfont/youmi.ttf#Mande uma mensagem privada para você e queira comprar nossa conta, mas sem usar a plataforma formal! nO preço está falsamente alto, com a intenção de atrair um acordo! nSaque de dinheiro de negociação, mas também taxas de trapaça!',
		text_th = '#Pfont/youmi1.ttf#การใช้งาน:n#Pfont/youmi.ttf#ส่งข้อความส่วนตัวถึงคุณและต้องการซื้อบัญชีของเรา แต่ไม่ต้องการใช้แพลตฟอร์มอย่างเป็นทางการ! nราคาสูงเกินจริง โดยมีจุดประสงค์เพื่อล่อให้ตกลงซื้อขาย! nการถอนเงินสดจากการซื้อขาย รวมถึงค่าธรรมเนียมการโกง!'
	},
	[8264] = {
		id = 8264,
		key = 'preventFraudPosterDes2',
		text = '#Pfont/youmi1.ttf#Friendly reminder:\n#Pfont/youmi.ttf#Don’t share accounts! \nDon\'t share order screenshots! \nDon\'t unbind you phone easily! \nPlease go to the formal platform for trading!',
		text_tw = '#Pfont/youmi1.ttf#友情提示：\n#Pfont/youmi.ttf#不要隨意共用賬號！\n不要共用訂單截圖！\n不要隨意解綁手機！\n交易請走正規平臺！',
		text_en = '#Pfont/youmi1.ttf#Friendly reminder:\n#Pfont/youmi.ttf#Don’t share accounts! \nDon\'t share order screenshots! \nDon\'t unbind you phone easily! \nPlease go to the formal platform for trading!',
		text_vn = '#Pfont/youmi1.ttf#LỜI NHẮC NHỞ:\n#Pfont/youmi.ttf#Đừng chia sẻ tài khoản của bạn một cách tùy tiện!\nĐừng chia sẻ ảnh chụp màn hình đơn hàng!\nĐừng tự ý hủy liên kết điện thoại!\nVui lòng sử dụng các nền tảng chính thức để giao dịch!',
		text_kr = '#Pfont/youmi1.ttf#친절한 알림:\n#Pfont/youmi.ttf#계정을 함부로 공유하지 마세요!\n주문 스크린샷을 공유하지 마세요!\n휴대폰을 함부로 해제하지 마세요!\n거래는 정식 플랫폼을 이용하세요!',
		text_pt = '#Pfont/youmi1.ttf#Lembrete amigável:n#Pfont/youmi.ttf#Não compartilhe contas! nNão compartilhe capturas de tela de pedidos! nNão desvincule seu telefone facilmente! nVá para a plataforma formal para negociação!',
		text_th = '#Pfont/youmi1.ttf#คำเตือนที่เป็นมิตร:n#Pfont/youmi.ttf#อย่าแชร์บัญชี! nอย่าแชร์ภาพหน้าจอคำสั่งซื้อ! nอย่าปลดการเชื่อมต่อโทรศัพท์ของคุณอย่างง่ายดาย! nโปรดไปที่แพลตฟอร์มอย่างเป็นทางการสำหรับการซื้อขาย!'
	},
