	[8486] = {
		id = 8486,
		key = 'volleyballGuide4',
		text = '#C0xF76B45#Long press the #C0x5B545B# charge button, the ball can be hit higher and farther, and power will gradually weaken after release',
		text_tw = '#C0xF76B45#長按#C0x5B545B#蓄力鍵，球可以打的更高更遠，鬆開後力量會逐漸減弱',
		text_en = '#C0xF76B45#Long press the #C0x5B545B# charge button, the ball can be hit higher and farther, and power will gradually weaken after release',
		text_vn = '#C0xF76B45#Nhấn giữ#C0x5B545B#nút tích năng, bóng có thể được đánh cao và xa hơn. Sức mạnh sẽ giảm dần sau khi thả ra.',
		text_kr = '축력 버튼을 #C0xF76B45#길게 누르면 #C0x5B545B#공을 더 높이 더 멀리 칠 수 있으며, 풀면 힘이 점점 약해진다.',
		text_pt = '#C0xF76B45#Pressione longamente o botão de carga #C0x5B545B#, a bola pode ser rebatida mais alto e mais longe, e a potência enfraquecerá gradualmente após a liberação',
		text_th = '#C0xF76B45# กดปุ่มชาร์จ #C0x5B545B# ค้างไว้ ลูกบอลจะถูกตีให้สูงขึ้นและไกลขึ้น และพลังจะค่อยๆ ลดน้อยลงหลังจากปล่อย'
	},
	[8487] = {
		id = 8487,
		key = 'volleyballGuide5',
		text = 'Every time #C0xF76B45# hits back #C0x5B545B# successfully, it will accumulate energy. When energy reaches certain amount can release skills, please use it reasonably',
		text_tw = '每次#C0xF76B45#成功回擊#C0x5B545B#都會積攢能量，達到檔位的能量可以釋放技能，請合理運用吧',
		text_en = 'Every time #C0xF76B45# hits back #C0x5B545B# successfully, it will accumulate energy. When energy reaches certain amount can release skills, please use it reasonably',
		text_vn = 'Mỗi lần phản công thành công #C0xF76B45# sẽ tích lũy năng lượng. Đạt đủ năng lượng theo cấp độ cho phép bạn tung ra kỹ năng. Hãy sử dụng một cách hợp lý!',
		text_kr = '매번 #C0xF76B45#리턴을 성공#C0x5B545B#할 때마다 에너지가 쌓이고, 레벨에 도달한 에너지는 스킬을 방출할 수 있으니 적절히 활용하세요.',
		text_pt = 'Toda vez que #C0xF76B45# revidar #C0x5B545B# com sucesso, ele acumulará energia. Quando a energia atinge certa quantidade pode liberar habilidades, por favor, use-a razoavelmente',
