	},
	[8488] = {
		id = 8488,
		key = 'volleyballGuide6',
		text = 'After tapping it, you can jump up and head the ball. When using  #C0xF76B45#charge #C0x5B545B# is #C0xF76B45#unable to jump#C0x5B545B#',
		text_tw = '點擊後可以跳起來頂球，在#C0xF76B45#蓄力#C0x5B545B#的時候是#C0xF76B45#無法起跳#C0x5B545B#的哦',
