	[8489] = {
		id = 8489,
		key = 'volleyballGuide7',
		text = 'If the opponent hits the ball to the out-of-bounds area, we will add #C0x5B545B# 1 point #C0xF76B45#, but if we hit it out of bounds by mistake #C0xF76B45# The opponent gets #C0x5B545B#1 point',
