	[8502] = {
		id = 8502,
		key = 'volleyballGuide9',
		text = '[Swift] Pokémons will be very swiftly, [Power] Pokémons will have a strong hitting power, [Huge] Pokémons can hit balls easily, please choose the Pokémon type you want to use.',
		text_tw = '【迅捷】精靈會很靈活，【力量】精靈擊球的力道會很強，【體積】精靈可打球的體積很大，請選擇您想使用的有優勢的精靈屬性吧',
		text_en = '[Swift] Pokémons will be very swiftly, [Power] Pokémons will have a strong hitting power, [Huge] Pokémons can hit balls easily, please choose the Pokémon type you want to use.',
		text_vn = '【Tốc độ】Pokémon sẽ rất nhanh nhẹn, 【Sức mạnh】Pokémon sẽ đánh bóng rất mạnh, 【Kích thước】Pokémon có diện tích đánh bóng rất lớn, hãy chọn thuộc tính Pokémon bạn muốn sử dụng có lợi thế nhé.',
		text_kr = '[신속] 포켓몬은 매우 민첩할 것이다, [힘] 포켓몬 타격의 힘은 매우 강할 것이다, [체적] 포켓몬은 공을 칠 수 있는 체적이 매우 크다, 사용하고 싶은 포켓몬 장점 속성을 선택하세요.',
		text_pt = 'Os Pokémon [rápidos] serão muito rápidos, os Pokémon [poderosos] terão um forte poder de ataque, os Pokémon [enormes] podem acertar bolas facilmente, escolha o tipo de Pokémon que deseja usar.',
		text_th = '[Swift] โปเกมอนจะว่องไวมาก [Power] โปเกมอนจะมีพลังโจมตีที่รุนแรง [Huge] โปเกมอนสามารถตีลูกบอลได้อย่างง่ายดาย กรุณาเลือกประเภทโปเกมอนที่คุณต้องการใช้'
	},
	[8503] = {
		id = 8503,
		key = 'volleyballGuide10',
		text = 'Tap Random, the system will randomly select an Pokémon with a attribute advantage and an opponent for you',
		text_tw = '點擊隨機，系統會為您隨機出屬性強勢的精靈和某一位對手',
		text_en = 'Tap Random, the system will randomly select an Pokémon with a attribute advantage and an opponent for you',
		text_vn = 'Nhấn Ngẫu nhiên, hệ thống sẽ tự động tạo ra một Pokémon có thuộc tính mạnh và một đối thủ.',
		text_kr = '랜덤을 누르면 시스템에서 해당 속성이 강한 포켓몬과 상대를 랜덤으로 매칭됩니다.',
		text_pt = 'Toque em Aleatório, o sistema selecionará aleatoriamente um Pokémon com uma vantagem de atributo e um oponente para você',
