	[8602] = {
		id = 8602,
		key = 'preliminaryMatchTip',
		text = '#C0x5B545B# Each battle group only has one guess chance. Do you want to use %d #Icommon/icon/icon_ghb.png-56-56# to guess the current guild?',
		text_tw = '該戰鬥組只有一次競猜機會，是否消耗%d公會幣競猜當前公會？',
		text_en = '#C0x5B545B# Each battle group only has one guess chance. Do you want to use %d #Icommon/icon/icon_ghb.png-56-56# to guess the current guild?',
		text_vn = '#C0x5B545B# Mỗi nhóm chiến đấu chỉ có một lần đoán. Bạn có muốn sử dụng %d #Icommon/icon/icon_ghb.png-56-56# để đoán hội hiện tại không?',
		text_kr = '#C0x5B545B# 각 전투 그룹은 한 번만 추측할 수 있습니다. %d #Icommon/icon/icon_ghb.png-56-56#을 사용하여 현재 길드를 추측하시겠습니까?',
		text_pt = '#C0x5B545B# para cada equipe há apenas uma chance de adivinhar, confirme para escolher: %s#Icommon/icon/icon_ghb.png-56-56# união atual？',
		text_th = '#C0x5B545B# สำหรับแต่ละทีมมีเพียงโอกาสเดียวในการเดา ยืนยันการเลือก: %s#Icommon/icon/icon_ghb.png-56-56# สหภาพปัจจุบัน？'
	},
	[8603] = {
		id = 8603,
		key = 'finalMatchTip',
		text = '#C0x5B545B#The finals only have one guess chance, do you want to spend %d #Icommon/icon/icon_ghb.png-56-56# guild coins to guess the current guild?',
		text_tw = '決賽只有一次競猜機會，是否消耗%d公會幣競猜當前公會？',
